import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { MaterialModule } from '../../../shared/material.module';
import { HttpClient } from '@angular/common/http';
import { environment } from '../../../../environments/environment';

@Component({
  selector: 'app-project-list',
  standalone: true,
  imports: [CommonModule, MaterialModule],
  templateUrl: './project-list.html',
  styleUrl: './project-list.css'
})
export class ProjectList implements OnInit {
  private http = inject(HttpClient);
  
  // Arreglo para almacenar los proyectos provenientes del backend
  proyectos: any[] = [];
  
  // Definición de columnas para mat-table
  displayedColumns: string[] = ['nombre', 'cliente', 'estado', 'acciones'];

  ngOnInit() {
    this.cargarProyectos();
  }

  cargarProyectos() {
    // Endpoint basado en los requerimientos de gestión
    this.http.get<any[]>(`${environment.apiUrl}/gestion/proyectos`).subscribe({
      next: (data) => {
        this.proyectos = data;
        console.log('Proyectos cargados exitosamente');
      },
      error: (err) => console.error('Error al conectar con NestJS:', err)
    });
  }

  // Colores de chips según los ENUM del SQL
  getEstadoColor(estado: string): string {
    switch (estado) {
      case 'ACTIVO': return 'primary';
      case 'FINALIZADO': return 'accent';
      case 'BAJA': return 'warn';
      default: return '';
    }
  }
}
